from flask import Flask, session, request, jsonify
import redis
import functools
import time
import json

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Connect to Redis
redis_client = redis.Redis(host='localhost', port=6379, db=0, decode_responses=True)

# Session management using Redis
@app.before_request
def load_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        session_data = redis_client.get(f"session:{session_id}")
        if session_data:
            session.update(json.loads(session_data))

@app.after_request
def save_session(response):
    session_id = session.get('session_id')
    if session_id:
        redis_client.setex(f"session:{session_id}", 3600, json.dumps(dict(session)))
    return response

# Caching decorator for expensive queries
def cache_result(expiration=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"cache:{func.__name__}:{hash(str(args) + str(kwargs))}"
            
            # Try to get from cache
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return json.loads(cached_result)
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, json.dumps(result))
            return result
        return wrapper
    return decorator

# Example expensive database query function
@cache_result(expiration=600)
def expensive_database_query(user_id):
    # Simulate expensive database operation
    time.sleep(2)
    return {"user_id": user_id, "data": f"Expensive data for user {user_id}"}

@app.route('/user/<int:user_id>')
def get_user(user_id):
    # This will be cached after first call
    result = expensive_database_query(user_id)
    return jsonify(result)

@app.route('/login', methods=['POST'])
def login():
    user_id = request.json.get('user_id')
    session['user_id'] = user_id
    session['session_id'] = f"session_{int(time.time())}"
    response = jsonify({"status": "logged_in"})
    response.set_cookie('session_id', session['session_id'])
    return response

@app.route('/logout', methods=['POST'])
def logout():
    session.clear()
    response = jsonify({"status": "logged_out"})
    response.set_cookie('session_id', '', expires=0)
    return response

if __name__ == '__main__':
    app.run(debug=False)